async function uptimeCommand() {
    const uptime = os.uptime();
    const days = Math.floor(uptime / 86400);
    const hours = Math.floor((uptime % 86400) / 3600);
    const minutes = Math.floor((uptime % 3600) / 60);

    return `⏱ *ÇALIŞMA SÜRESİ*\n\n${days} gün, ${hours} saat, ${minutes} dakika`;
}

async function processListCommand() {
    return new Promise((resolve) => {
        exec('tasklist /fo csv', (error, stdout) => {
            if (error) {
                resolve('❌ İşlem listesi alınamadı');
                return;
            }

            const processes = stdout.trim().split('\n').slice(1, 16);
            let output = '🔄 *İŞLEMLER* (ilk 15)\n\n';

            processes.forEach((proc, index) => {
                const parts = proc.split(',');
                const name = parts[0].replace(/"/g, '');
                const mem = parts[4] ? parts[4].replace(/"/g, '') : '-';
                output += `${index + 1}. ${name} - ${mem}\n`;
