const express = require('express');
const cors = require('cors');
const http = require('http');
const { Server } = require('socket.io');
const { Client, LocalAuth } = require('whatsapp-web.js');
const QRCode = require('qrcode');
const path = require('path');
const fs = require('fs');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
    cors: {
        origin: "*",
        methods: ["GET", "POST"]
    }
});

// Middleware
app.use(cors());
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

// WhatsApp Client
const client = new Client({
    authStrategy: new LocalAuth(),
    puppeteer: {
        headless: true,
        args: ['--no-sandbox', '--disable-setuid-sandbox']
    }
});

// Store messages
let messages = [];
let contacts = [];

// WhatsApp Events
client.on('qr', (qr) => {
    console.log('QR Received');
    QRCode.toDataURL(qr, (err, url) => {
        if (err) {
            console.error('QR Error:', err);
            return;
        }
        io.emit('qr', url);
    });
});

client.on('ready', () => {
    console.log('WhatsApp Ready!');
    io.emit('ready', {
        message: 'WhatsApp bağlandı!',
        info: client.info
    });

    // Load contacts
    client.getChats().then(chats => {
        contacts = chats.map(chat => ({
            id: chat.id._serialized,
            name: chat.name || chat.id.user,
            lastMessage: chat.lastMessage?.body || '',
            timestamp: chat.timestamp
        }));
        io.emit('contacts', contacts);
    });
});

// Bulut AI Bot
const BOT_TRIGGER = '!bulut';
const botCommands = require('./bot-commands');

client.on('message', async (msg) => {
    const contact = await msg.getContact();
    const messageData = {
        id: msg.id._serialized,
        from: msg.from,
        to: msg.to,
        body: msg.body,
        type: msg.type,
        timestamp: msg.timestamp,
        sender: {
            id: contact.id._serialized,
            name: contact.pushname || contact.shortName,
            profilePic: contact.profilePicUrl
        }
    };

    messages.push(messageData);
    io.emit('message', messageData);

    // Check if message is directed to Bulut Bot
    const body = msg.body.trim();

    // Direct message to bot or bot command
    if (body.toLowerCase().startsWith(BOT_TRIGGER) || body.startsWith('☁️') || body.startsWith('Bulut')) {
        try {
            // Typing indicator
            await msg.reply('⌨️ Yazıyor...');

            // Process command
            const response = await botCommands.processCommand(body, msg, client);

            // Send response
            if (response) {
                await msg.reply(response);
            }
        } catch (error) {
            console.error('Bot Error:', error);
            await msg.reply('❌ Bir hata oluştu: ' + error.message);
        }
    }
});

client.on('disconnected', (reason) => {
    console.log('WhatsApp Disconnected:', reason);
    io.emit('disconnected', { reason });
});

client.initialize();

// API Routes

// Get all messages
app.get('/api/messages', (req, res) => {
    res.json(messages);
});

// Get contacts
app.get('/api/contacts', (req, res) => {
    res.json(contacts);
});

// Send message
app.post('/api/send-message', async (req, res) => {
    try {
        const { chatId, message } = req.body;
        const result = await client.sendMessage(chatId, message);
        res.json({ success: true, result });
    } catch (error) {
        res.status(500).json({ success: false, error: error.message });
    }
});

// Get QR Code
app.get('/api/qr', (req, res) => {
    res.json({ status: 'waiting' });
});

// Get connection status
app.get('/api/status', (req, res) => {
    res.json({
        connected: client.info !== null,
        info: client.info
    });
});

// Remote control - Execute command
app.post('/api/remote/command', async (req, res) => {
    try {
        const { command, params } = req.body;
        let result;

        switch(command) {
            case 'getChats':
                result = await client.getChats();
                break;
            case 'getMessages':
                result = await client.getMessages(params.chatId);
                break;
            case 'sendMessage':
                result = await client.sendMessage(params.chatId, params.message);
                break;
            case 'deleteChat':
                result = await client.deleteChat(params.chatId);
                break;
            case 'archiveChat':
                result = await client.archiveChat(params.chatId);
                break;
            default:
                return res.status(400).json({ success: false, error: 'Unknown command' });
        }

        res.json({ success: true, result });
    } catch (error) {
        res.status(500).json({ success: false, error: error.message });
    }
});

// Serve frontend
app.get('/', (req, res) => {
    res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

// Start server
const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
    console.log(`Server running on http://localhost:${PORT}`);
    console.log(`Remote access: http://YOUR_IP:${PORT}`);
});

